-- Case 004: PIVOT, UNPIVOT, and GROUPING SETS in one report
WITH monthly AS(SELECT DATE_PART( 'year',order_date) AS order_year,DATE_PART( 'month',order_date) AS order_month,region,channel,SUM(net_amount) AS net_amount,COUNT(DISTINCT customer_id) AS buyers FROM MART.FACT_ORDERS WHERE order_date >= DATE_FROM_PARTS(YEAR(CURRENT_DATE()) - 1,1,1) GROUP BY order_year,order_month,region,channel),pivoted AS(SELECT * FROM monthly PIVOT(SUM(net_amount) FOR order_month IN(1 AS JAN,2 AS FEB,3 AS MAR,4 AS APR,5 AS MAY,6 AS JUN,7 AS JUL,8 AS AUG,9 AS SEP,10 AS OCT,11 AS NOV,12 AS DEC))),unpivoted AS(SELECT order_year,region,channel,month_name,net_amount FROM pivoted UNPIVOT INCLUDE NULLS(net_amount FOR month_name IN(JAN,FEB,MAR,APR,MAY,JUN,JUL,AUG,SEP,OCT,NOV,DEC))),grouped AS(SELECT order_year,region,channel,month_name,GROUPING(order_year) AS g_year,GROUPING(region) AS g_region,GROUPING(channel) AS g_channel,GROUPING(month_name) AS g_month,SUM(net_amount) AS total_net_amount,AVG(NULLIF(net_amount,0)) AS avg_active_month_amount FROM unpivoted GROUP BY GROUPING SETS((order_year,region,channel,month_name),(order_year,region,channel),(order_year,region),(order_year),())) SELECT IFF(g_year = 1, '<ALL_YEARS>',TO_VARCHAR(order_year)) AS year_label,IFF(g_region = 1, '<ALL_REGIONS>',region) AS region_label,IFF(g_channel = 1, '<ALL_CHANNELS>',channel) AS channel_label,IFF(g_month = 1, '<ALL_MONTHS>',month_name) AS month_label,total_net_amount,avg_active_month_amount,RANK() OVER(PARTITION BY g_year,order_year,g_region,region ORDER BY total_net_amount DESC NULLS LAST) AS amount_rank FROM grouped WHERE COALESCE(total_net_amount,0) <> 0 ORDER BY year_label,region_label,channel_label,month_label;
